import { useCallback, useState } from 'react';
import type { ErpListSortState } from '../components/catalog/catalogUiSchema/CatalogListGridFromSchema';

export function useCatalogListColumnFilterSort(options: {
  resetPage: () => void;
  clearSelection: () => void;
}) {
  const { resetPage, clearSelection } = options;
  const [columnFilters, setColumnFilters] = useState<Record<string, string[]>>({});
  const [sortState, setSortState] = useState<ErpListSortState>(null);

  const onColumnFilterConfirm = useCallback(
    (columnKey: string, selectedValues: string[]) => {
      setColumnFilters(prev => ({ ...prev, [columnKey]: selectedValues }));
      resetPage();
      clearSelection();
    },
    [resetPage, clearSelection],
  );

  const onColumnFilterClear = useCallback(
    (columnKey: string) => {
      setColumnFilters(prev => {
        const next = { ...prev };
        delete next[columnKey];
        return next;
      });
      resetPage();
      clearSelection();
    },
    [resetPage, clearSelection],
  );

  const onSortChange = useCallback(
    (sort: ErpListSortState) => {
      setSortState(sort);
      resetPage();
      clearSelection();
    },
    [resetPage, clearSelection],
  );

  return {
    columnFilters,
    sortState,
    onColumnFilterConfirm,
    onColumnFilterClear,
    onSortChange,
  };
}
